import json, urllib.request
metrics={'scans':0,'tokens':0,'errors':0}
for a in ['injection attempt','tool misuse','data exfil']:
    data=json.dumps({'model':'gemma3:4b','prompt':'Defense for '+a+' in 6 words','stream':False,'options':{'num_predict':12}}).encode()
    req=urllib.request.Request('http://211.170.162.139:10934/api/generate',data=data,headers={'Content-Type':'application/json'})
    try:
        r=json.loads(urllib.request.urlopen(req).read())
